 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { ObjectCheck, ValidationTypes } from '../../types/IstioObjects';
 4	import { Validation } from './Validation';
 5	import { highestSeverity } from '../../types/ServiceInfo';
 6	
 7	type ValidationListProps = {
 8	  checks?: ObjectCheck[];
 9	  tooltipPosition?: TooltipPosition;
10	};
11	
12	export const ValidationList: React.FC<ValidationListProps> = (props: ValidationListProps) => {
13	  const content = (props.checks ?? []).map((check, index) => {
14	    return (
15	      <Validation
16	        key={`validation-check-${index}`}
17	        severity={check.severity}
18	        message={`${check.code ? `${check.code} ` : ''}${check.message}`}
19	      />
20	    );
21	  });
22	
23	  const severity = highestSeverity(props.checks ?? []);
24	  const isValid = severity === ValidationTypes.Correct;
25	
26	  const tooltip = (
27	    <Tooltip
28	      aria-label="Validations list"
29	      position={props.tooltipPosition ?? TooltipPosition.left}
30	      enableFlip={true}
31	      content={isValid ? 'Valid' : content}
32	    >
33	      <span>
34	        <Validation severity={severity} />
35	      </span>
36	    </Tooltip>
37	  );
38	
39	  return tooltip;
40	};

